const status = (node) => {
  try {
    const d = $(node).first().json;
    return (!d || d.statusCode >= 400 || d.error || d.code === 'ECONNREFUSED') ? 'вќЊ Down' : 'вњ… Online';
  } catch(e) { return 'вќЊ Down'; }
};

const radarrQueue = $('Radarr Queue').first().json?.totalRecords ?? 0;
const sonarrQueue = $('Sonarr Queue').first().json?.totalRecords ?? 0;

// Parse prometheus metrics
const parseMetric = (text, name) => {
  const match = text.match(new RegExp(`^${name}\\s+([\\d.e+]+)`, 'm'));
  return match ? parseFloat(match[1]) : null;
};

const parseMetricLabeled = (text, name, label) => {
  const match = text.match(new RegExp(`^${name}\\{[^}]*${label}[^}]*\\}\\s+([\\d.e+]+)`, 'm'));
  return match ? parseFloat(match[1]) : null;
};

let sysSection = 'Unavailable';
try {
  const metrics = $('System Metrics').first().json;
  const raw = typeof metrics === 'string' ? metrics : (metrics.data ?? metrics.body ?? '');

  const memAvail = parseMetric(raw, 'windows_os_physical_memory_free_bytes');
  const memTotal = parseMetric(raw, 'windows_os_visible_memory_bytes');
  const memUsedPct = memTotal && memAvail ? Math.round((1 - memAvail / memTotal) * 100) : null;

  // Disk free for D:
  const diskFreeMatch = raw.match(/windows_logical_disk_free_bytes\{volume="D:"\}\s+([\d.e+]+)/);
  const diskTotalMatch = raw.match(/windows_logical_disk_size_bytes\{volume="D:"\}\s+([\d.e+]+)/);
  const diskFreeGB = diskFreeMatch ? (parseFloat(diskFreeMatch[1]) / 1e9).toFixed(0) : null;
  const diskTotalGB = diskTotalMatch ? (parseFloat(diskTotalMatch[1]) / 1e9).toFixed(0) : null;

  // Thermalzone temps
  const tempMatches = [...raw.matchAll(/windows_thermalzone_temperature_celsius\{[^}]+\}\s+([\d.e+]+)/g)];
  const temps = tempMatches.map(m => parseFloat(m[1]).toFixed(1));
  const maxTemp = temps.length ? Math.max(...temps.map(Number)).toFixed(1) : null;

  sysSection = [
    memUsedPct !== null ? `RAM Usage:           ${memUsedPct}% (${((memTotal - memAvail)/1e9).toFixed(1)} / ${(memTotal/1e9).toFixed(1)} GB)` : 'RAM Usage:           Unavailable',
    diskFreeGB !== null ? `Disk D: Free:        ${diskFreeGB} GB / ${diskTotalGB} GB` : 'Disk D: Free:        Unavailable',
    maxTemp !== null ? `Peak Temp:           ${maxTemp}В°C` : 'Peak Temp:           Unavailable',
  ].join('\n');
} catch(e) {
  sysSection = 'Error reading metrics: ' + e.message;
}

// Indexer health via Prowlarr API (no tracker hits вЂ” reads cached failure status)
let indexerSection = 'Unavailable';
try {
  const http = require('http');
  const KEY = $env.PROWLARR_KEY;
  const pget = (path) => new Promise((resolve) => {
    const r = http.request({ host: 'prowlarr', port: 9696, path: path, method: 'GET', headers: { 'X-Api-Key': KEY } }, (res) => {
      let b = '';
      res.on('data', (c) => { b += c; });
      res.on('end', () => { try { resolve(JSON.parse(b || 'null')); } catch (e) { resolve(null); } });
    });
    r.on('error', () => resolve(null));
    r.end();
  });
  const statusArr = (await pget('/api/v1/indexerstatus')) || [];
  const indexers = (await pget('/api/v1/indexer')) || [];
  const nameById = {};
  for (const i of indexers) { nameById[i.id] = i.name; }
  const now = Date.now();
  const failing = statusArr.filter((s) => s.disabledTill && new Date(s.disabledTill).getTime() > now);
  if (indexers.length === 0) {
    indexerSection = 'No indexers configured';
  } else if (failing.length === 0) {
    indexerSection = `All ${indexers.length} indexer(s) healthy`;
  } else {
    const lines = failing.map((s) => `  ${nameById[s.indexerId] || ('id ' + s.indexerId)} вЂ” failing (retry after ${new Date(s.disabledTill).toLocaleString()})`);
    indexerSection = `${failing.length} of ${indexers.length} indexer(s) failing:\n` + lines.join('\n');
  }
} catch (e) {
  indexerSection = 'Error reading indexer status: ' + e.message;
}

